#include <bits/stdc++.h>
using namespace std;
const int maxn=2e5+5;
int a[maxn],dp[maxn],ans=INT_MIN,q[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	memset(dp,-0x3f,sizeof(dp));
	int n,l,r;
	cin>>n>>l>>r;
	if(n==0){
		cout<<0;
		return 0;
	}
	dp[0]=0;
	int h=1,t=0;
	for(int i=0;i<=n;i++){
		cin>>a[i];
	}
	q[h]=1;
	for(int i=l; i<=n; i++) {
		int cur=i-l;
		while(h<=t&&dp[q[t]]<=dp[cur]) {
			t--;
		}
		q[++t]=cur;
		while(h<=t&&q[h]<i-r) {
			h++;
		}
		if(h<=t&&dp[q[h]]>=-1e9){
			dp[i]=dp[q[h]]+a[i];
		}
		if(i+r>n){
			ans=max(ans,dp[i]);
		}
	}
	cout<<ans;
	return 0;
}
